#[tokio::test]
async fn test_admin_withdraw_requires_signer() {
    let malicious_tx = Transaction::new_signed_with_payer(
        &[instruction::admin_withdraw(&program_id, &context_accounts, vault.lamports - rent_exempt)],
        Some(&payer.pubkey()),
        &[&payer],  // Only payer signs — admin does NOT sign
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&malicious_tx).await;
    assert!(result.is_err());  // Must fail with NotSigner
}

#[test]
fn test_hardcoded_bump_collision() {
    // Attacker finds alternative bump producing same PDA
    let canonical_bump = Pubkey::find_program_address(&[b"vault", user.as_ref()], &program_id).1;
    let attacker_bump = (0u8..255).find(|&b| {
        Pubkey::create_program_address(&[b"vault", user.as_ref(), &[b]], &program_id).is_ok()
    }).unwrap();
    assert_ne!(canonical_bump, attacker_bump, "non-canonical bump must differ from canonical");
}

#[tokio::test]
async fn test_cpi_rejects_unauthorized_program() {
    let malicious_tx = Transaction::new_signed_with_payer(
        &[instruction::exec_callback(&program_id, &[], &malicious_program.pubkey())],
        Some(&user.pubkey()),
        &[&user],
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&malicious_tx).await;
    assert!(result.is_err());  // Must fail with UnauthorizedProgram
}

#[tokio::test]
async fn test_drain_vault_requires_authority() {
    let drain_tx = Transaction::new_signed_with_payer(
        &[instruction::drain_vault(&program_id, &vault_pda, &attacker.pubkey())],
        Some(&attacker.pubkey()),
        &[&attacker],  // No authority signer
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&drain_tx).await;
    assert!(result.is_err());  // Must fail — no authority signer
}

#[test]
fn test_overflow_returns_error() {
    let max = u64::MAX;
    let result = max.checked_add(1);
    assert!(result.is_none(), "checked_add must return None on overflow");
    let wrapped = max.wrapping_add(1);
    assert_eq!(wrapped, 0, "wrapping_add silently wraps — use checked_add");
}

#[tokio::test]
async fn test_initialize_rejects_reinit() {
    program.rpc().process_transaction(&init_tx).await.unwrap();
    program.rpc().process_transaction(&close_tx).await.unwrap();
    program.rpc().process_transaction(&refund_tx).await.unwrap();
    let result = program.rpc().process_transaction(&init_tx).await;
    assert!(result.is_err());  // Must fail with AlreadyInitialized
}
